+    private func withTimeout<T>(
+        seconds: Int,
+        purpose: String,
+        _ op: @escaping @Sendable () async throws -> T) async throws -> T
+    {
+        try await withThrowingTaskGroup(of: T.self) { group in
+            group.addTask {
+                try await op()
+            }
+            group.addTask {
+                try await Task.sleep(nanoseconds: UInt64(seconds) * 1_000_000_000)
+                throw TimeoutError(purpose: purpose, seconds: seconds)
+            }
+            let result = try await group.next()!
+            group.cancelAll()
+            return result
+        }
+    }
+
+    private func startAndWaitForReady(_ connection: NWConnection, queue: DispatchQueue) async throws {
+        try await withCheckedThrowingContinuation(isolation: nil) { (cont: CheckedContinuation<Void, Error>) in
+            var didResume = false
+            connection.stateUpdateHandler = { state in
+                if didResume { return }
+                switch state {
+                case .ready:
+                    didResume = true
+                    cont.resume(returning: ())
+                case let .failed(err):
+                    didResume = true
+                    cont.resume(throwing: err)
+                case let .waiting(err):
+                    didResume = true
+                    cont.resume(throwing: err)
+                case .cancelled:
+                    didResume = true
+                    cont.resume(throwing: NSError(domain: "Bridge", code: 50, userInfo: [
+                        NSLocalizedDescriptionKey: "Connection cancelled",
+                    ]))
+                default:
+                    break
+                }
+            }
+            connection.start(queue: queue)
+        }
+    }
